// Compiled query — define 1 lần, dùng mãi
private static readonly Func<AppDbContext, int, Task<User?>> GetUserById =
    EF.CompileAsyncQuery(
        (AppDbContext db, int id) => db.Users.FirstOrDefault(u => u.Id == id));

private static readonly Func<AppDbContext, string, IAsyncEnumerable<Order>> GetOrdersByStatus =
    EF.CompileAsyncQuery(
        (AppDbContext db, string status) =>
            db.Orders
              .Where(o => o.Status == status)
              .OrderByDescending(o => o.CreatedAt)
              .Select(o => new { o.Id, o.Status, o.CreatedAt }));

// Sử dụng — zero compilation overhead
public async Task<User?> GetUserAsync(int id, CancellationToken ct)
{
    await using var db = await _factory.CreateDbContextAsync(ct);
    return await GetUserById(db, id);
}

